+            sum = _mm512_add_ps(sum, abs_diff);
+        }
+    }
+
+    let mut result = _mm512_reduce_add_ps(sum);
+
+    // Handle remainder
+    for i in (chunks * 16)..len {
+        result += (*a.add(i) - *b.add(i)).abs();
+    }
+
+    result
+}
